    name_en text,
    slug text,
    origin text,
    description text,
    fruit_size text,
    taste text,
    texture text,
    aroma text,
    harvest_season text,
    tree_vigor text,
    difficulty text,
    okinawa_suitability text,
    container_suitability text,
    beginner_suitability text,
    kenyu_comment text,
    public_notes text,
    private_notes text,
    is_public boolean,
    is_for_sale boolean
  )
)
